import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"开户被拒怎么办","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/opening/account-rejected.md","filePath":"zh-CN/account/opening/account-rejected.md"}'),o={name:"account/opening/account-rejected.md"};function n(i,t,h,l,c,s){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="开户被拒怎么办" tabindex="-1">开户被拒怎么办 <a class="header-anchor" href="#开户被拒怎么办" aria-label="Permalink to &quot;开户被拒怎么办&quot;">​</a></h1><p>开户申请被驳回时，App 内会显示驳回原因。按原因对应处理后可重新提交。</p><h2 id="常见驳回原因及处理方式" tabindex="-1">常见驳回原因及处理方式 <a class="header-anchor" href="#常见驳回原因及处理方式" aria-label="Permalink to &quot;常见驳回原因及处理方式&quot;">​</a></h2><h3 id="证件问题" tabindex="-1">证件问题 <a class="header-anchor" href="#证件问题" aria-label="Permalink to &quot;证件问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原因</th><th>处理方式</th></tr></thead><tbody><tr><td>证件照片不清晰或反光</td><td>在光线充足的环境下重新拍摄，确保四角完整、无遮挡</td></tr><tr><td>证件已过期</td><td>使用有效期内的证件，身份证需满足 6 个月有效期</td></tr><tr><td>证件与填写信息不符</td><td>检查姓名、证件号、出生日期是否与证件完全一致</td></tr><tr><td>不支持的证件类型</td><td>需提供身份证或护照，部分地区的驾驶证需人工审核</td></tr></tbody></table><h3 id="地区与身份限制" tabindex="-1">地区与身份限制 <a class="header-anchor" href="#地区与身份限制" aria-label="Permalink to &quot;地区与身份限制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原因</th><th>处理方式</th></tr></thead><tbody><tr><td>美国 / 加拿大证件或居民</td><td>长桥暂不支持美国和加拿大证件或居民开户</td></tr><tr><td>所在地区不在支持范围内</td><td>参考<a href="/wiki/compliance-and-tax/哪些国家和地区可以开户">哪些国家和地区可以开户</a></td></tr><tr><td>大陆居民缺少海外生活证明</td><td>需补充新加坡或其他海外签证实体卡（新加坡账户要求）</td></tr></tbody></table><h3 id="身份认证未完成" tabindex="-1">身份认证未完成 <a class="header-anchor" href="#身份认证未完成" aria-label="Permalink to &quot;身份认证未完成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原因</th><th>处理方式</th></tr></thead><tbody><tr><td>入金见证金额不足</td><td>香港账户入金见证需一次性入金 10,000 HKD 或 1,500 USD 以上</td></tr><tr><td>第三方见证材料未寄达</td><td>确认邮寄已成功，在 App 内点击「已寄出」确认</td></tr><tr><td>人脸识别失败</td><td>在光线充足环境下重新进行，确保面部无遮挡</td></tr><tr><td>CA 验证未通过（大陆用户）</td><td>重新进行人脸识别，或联系客服确认银联卡绑定状态</td></tr></tbody></table><h3 id="适当性评估未通过" tabindex="-1">适当性评估未通过 <a class="header-anchor" href="#适当性评估未通过" aria-label="Permalink to &quot;适当性评估未通过&quot;">​</a></h3><p>长桥须依据法规评估投资者适当性。若评估分数不足，建议：</p><ol><li>如实填写投资经验和资产情况，不要故意低估</li><li>如确实缺乏相关经验，可选择以学习为目的的模拟账户先行熟悉</li><li>部分评估有冷却期，需等待一段时间后重新申请</li></ol><h2 id="重新提交申请" tabindex="-1">重新提交申请 <a class="header-anchor" href="#重新提交申请" aria-label="Permalink to &quot;重新提交申请&quot;">​</a></h2><p>修正问题后，在 App → 资产 → 开户申请 → 继续申请，从驳回的步骤重新提交，无需从头填写。</p><h2 id="联系客服" tabindex="-1">联系客服 <a class="header-anchor" href="#联系客服" aria-label="Permalink to &quot;联系客服&quot;">​</a></h2><p>如驳回原因不明确，或需要协助处理特殊情况，请联系客服：</p><p><strong>在线客服</strong>：长桥 App → 我的 → 帮助与客服 → 在线客服<br><strong>香港邮箱</strong>：service@longbridge.hk<br><strong>新加坡邮箱</strong>：contact@longbridge.sg</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/account">开户与账户</a></li></ul>',19)])])}const p=a(o,[["render",n]]);export{u as __pageData,p as default};
